   517|async function walkRepo(projectRoot: string, current: string, state: { files: string[]; dirs: number }): Promise<void> {
   518|  if (state.files.length >= MAX_INDEXED_FILES) return;
   519|  const entries = await readdir(current, { withFileTypes: true });
   520|  for (const entry of entries) {
   521|    if (state.files.length >= MAX_INDEXED_FILES) break;
   522|    const fullPath = path.join(current, entry.name);
   523|    const relative = relativeFromRoot(projectRoot, fullPath);
   524|    if (entry.isDirectory()) {
   525|      if (IGNORED_DIRECTORIES.includes(entry.name)) continue;
   526|      state.dirs += 1;
   527|      await walkRepo(projectRoot, fullPath, state);
   528|      continue;
   529|    }
   530|    if (entry.isFile()) {
   531|      state.files.push(relative);
   532|    }
   533|  }
   534|}
